def luminance(r, g, b):
    def f(c):
        c = c / 255.0
        return c / 12.92 if c <= 0.04045 else ((c + 0.055) / 1.055) ** 2.4
    return 0.2126 * f(r) + 0.7152 * f(g) + 0.0722 * f(b)
def contrast(l1, l2):
    return (max(l1,l2)+0.05)/(min(l1,l2)+0.05)
bg = luminance(0x5b, 0x52, 0xe0)
fg = luminance(0xff, 0xff, 0xff)
print(f'consent accept (#fff on #5b52e0): {contrast(fg, bg):.1f}:1')
"

