  line-height: 1.6;
}

.footer-links h4 {
  color: #fff;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 1rem;
}

.footer-links ul {
  list-style: none;
}
.footer-links li {
  margin-bottom: 0.5rem;
}
.footer-links a {
  color: rgba(255, 255, 255, 0.6);
  font-size: 0.9rem;
}
.footer-links a:hover {
  color: #fff;
}

